(excluded.recent_run_home,live_game_visual_state.recent_run_home),recent_run_away=coalesce(excluded.recent_run_away,live_game_visual_state.recent_run_away),recent_scoring_drought_home_sec=coalesce(excluded.recent_scoring_drought_home_sec,live_game_visual_state.recent_scoring_drought_home_sec),recent_scoring_drought_away_sec=coalesce(excluded.recent_scoring_drought_away_sec,live_game_visual_state.recent_scoring_drought_away_sec),pace_estimate=coalesce(excluded.pace_estimate,live_game_visual_state.pace_estimate),in_bonus_home=coalesce(excluded.in_bonus_home,live_game_visual_state.in_bonus_home),in_bonus_away=coalesce(excluded.in_bonus_away,live_game_visual_state.in_bonus_away),home_fouls_period=coalesce(excluded.home_fouls_period,live_game_visual_state.home_fouls_period),away_fouls_period=coalesce(excluded.away_fouls_period,live_game_visual_state.away_fouls_period),sync_latency_ms=coalesce(excluded.sync_latency_ms,live_game_visual_state.sync_latency_ms),visual_mode_enabled=coalesce(excluded.visual_mode_enabled,live_game_visual_state.visual_mode_enabled),parser_version=coalesce(excluded.parser_version,live_game_visual_state.parser_version),source_provider=coalesce(excluded.source_provider,live_game_visual_state.source_provider),last_source_event_id=coalesce(excluded.last_source_event_id,live_game_visual_state.last_source_event_id),last_ingested_at=coalesce(excluded.last_ingested_at,live_game_visual_state.last_ingested_at),updated_at=now(); end; $function$;